#include <vector>
#include <algorithm>

using namespace std;

int maxScore(vector<int>& nums) {
    int n = nums.size() / 2;
    sort(nums.begin(), nums.end());
    int score = 0;
    for (int i = 0; i < n; ++i) {
        score += (i + 1) * __gcd(nums[i], nums[n + i]);
    }
    return score;
}

int gcd(int a, int b) {
    if (b == 0) {
        return a;
    }
    return gcd(b, a % b);
}
```
